{"cmd":"python3 - <<'PY'
import re, pathlib, struct
exe=pathlib.Path('handout/RecordPlayer.exe').read_bytes()
text=pathlib.Path('/tmp/recordplayer.iR.txt').read_text().splitlines()
res=[]
cur={}
for line in text:
    line=line.strip()
    if line.startswith('Resource '):
        if cur: res.append(cur); cur={}
    elif line.startswith('name:'):
        cur['name']=line.split(':',1)[1].strip()
    elif line.startswith('vaddr:'):
        cur['vaddr']=int(line.split(':',1)[1].strip(),16)
    elif line.startswith('size:'):
        s=line.split(':',1)[1].strip()
        # parse values like 2.7K, 226.6K, 703.8K, 170
        if s.endswith('K'):
            cur['size']=int(float(s[:-1])*1024)
        else:
            cur['size']=int(float(s))
    elif line.startswith('type:'):
        cur['type']=line.split(':',1)[1].strip().split()[0]
if cur: res.append(cur)

base_v=0x14000b000
base_p=0x7e00
out=pathlib.Path('/tmp/recordplayer_res')
out.mkdir(exist_ok=True)
for r in res:
    if r.get('type') in {'BITMAP','DIALOG','UNKNOWN','SOUND'} and r.get('name') in {'102','103','104','105','106','107','110','127','128','129','130','101','132','134','141','111'}:
        off=base_p + (r['vaddr']-base_v)
        data=exe[off:off+r['size']]
        fname=f"{r['type']}_{r['name']}.bin"
        if r['type']=='BITMAP':
            fname=f"bmp_{r['name']}.bin"
        elif r['type']=='DIALOG':
            fname=f"dlg_{r['name']}.bin"
        elif r['type']=='SOUND':
            fname=f"snd_{r['name']}.wav"
        (out/fname).write_bytes(data)
        print(r['type'],r['name'],'size',r['size'],'off',hex(off), '->', fname)
print('files',len(list(out.iterdir())))
PY
ls -lh /tmp/recordplayer_res | sed -n '1,120p'
for f in /tmp/recordplayer_res/bmp_102.bin /tmp/recordplayer_res/bmp_103.bin /tmp/recordplayer_res/bmp_104.bin /tmp/recordplayer_res/bmp_105.bin /tmp/recordplayer_res/bmp_106.bin /tmp/recordplayer_res/bmp_107.bin; do echo "== $f"; file "$f"; done"}
